import { ReactNode } from 'react';

export interface Project {
  title: string;
  subtitle: string;
  description: string;
  features: string[];
  tags: string[];
  github: string;
  diagram: ReactNode;
  highlight: string;
}

export interface Skill {
  name: string;
  level: string;
  desc: string;
  icon: ReactNode;
}

export interface SkillCategory {
  title: string;
  skills: Skill[];
}

export interface ChatMessage {
  role: 'user' | 'assistant';
  text: string;
  isStreaming?: boolean;
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { RESUME_CONTEXT } from "../constants";

export const getGeminiResponse = async (prompt: string): Promise<string> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: RESUME_CONTEXT,
        temperature: 0.7,
        topP: 0.8,
        topK: 40,
      },
    });
    return response.text || "I'm sorry, I couldn't generate a response.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "I'm having a bit of trouble connecting to my brain right now. Please try again later!";
  }
};

export const getGeminiStream = async (prompt: string, onChunk: (text: string) => void) => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
    const result = await ai.models.generateContentStream({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: RESUME_CONTEXT,
      },
    });

    let fullText = "";
    for await (const chunk of result) {
      const chunkText = chunk.text || "";
      fullText += chunkText;
      onChunk(fullText);
    }
  } catch (error) {
    console.error("Gemini Streaming Error:", error);
    onChunk("I encountered an error while thinking. Please try again.");
  }
};

export const analyzeProjectDepth = async (projectTitle: string, projectDesc: string): Promise<string> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
    const prompt = `Provide a deep technical analysis of the project "${projectTitle}". 
    Description: ${projectDesc}
    Format the response as 3 professional bullet points covering:
    1. Technical Innovation
    2. Architecture Strengths
    3. Scalability Roadmap`;

    const response: GenerateContentResponse = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.5,
      }
    });
    return response.text || "Analysis unavailable.";
  } catch (error) {
    return "Could not perform deep analysis at this time.";
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { 
  MessageSquare, 
  Send, 
  X, 
  Bot, 
  Loader2, 
  Sparkles,
  Maximize2,
  Minimize2
} from 'lucide-react';
import { getGeminiStream } from '../services/geminiService';
import { ChatMessage } from '../types';

export const AIChat: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [isMinimized, setIsMinimized] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'assistant', text: "Hi! I'm Anup's Virtual Assistant. Want to know about his IEEE paper, web skills, or how he can help your team? Ask me anything! ✨" }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isOpen]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;

    const userText = input.trim();
    setMessages(prev => [...prev, { role: 'user', text: userText }]);
    setInput('');
    setIsTyping(true);

    // Placeholder for streaming
    setMessages(prev => [...prev, { role: 'assistant', text: '', isStreaming: true }]);

    await getGeminiStream(userText, (updatedText) => {
      setMessages(prev => {
        const last = prev[prev.length - 1];
        if (last && last.role === 'assistant' && last.isStreaming) {
          return [...prev.slice(0, -1), { role: 'assistant', text: updatedText, isStreaming: true }];
        }
        return prev;
      });
    });

    setMessages(prev => {
      const last = prev[prev.length - 1];
      if (last) {
        return [...prev.slice(0, -1), { role: 'assistant', text: last.text, isStreaming: false }];
      }
      return prev;
    });
    setIsTyping(false);
  };

  if (!isOpen) {
    return (
      <button 
        onClick={() => setIsOpen(true)}
        className="fixed bottom-6 right-6 z-50 p-4 bg-teal-600 text-white rounded-full shadow-2xl hover:bg-teal-500 transition-all hover:scale-110 active:scale-95 group"
      >
        <MessageSquare size={24} />
        <span className="absolute right-full mr-4 top-1/2 -translate-y-1/2 bg-slate-800 text-teal-400 px-3 py-1.5 rounded-lg text-xs font-bold whitespace-nowrap opacity-0 group-hover:opacity-100 transition-opacity border border-slate-700 pointer-events-none">
          Talk to Virtual Anup
        </span>
      </button>
    );
  }

  return (
    <div className={`fixed bottom-6 right-6 z-50 flex flex-col glass-card rounded-2xl shadow-2xl overflow-hidden transition-all duration-300 ${isMinimized ? 'h-14 w-64' : 'h-[500px] w-[350px] md:w-[400px]'}`}>
      {/* Header */}
      <div className="bg-slate-800/80 p-4 border-b border-white/10 flex justify-between items-center cursor-pointer" onClick={() => isMinimized && setIsMinimized(false)}>
        <div className="flex items-center gap-2">
          <div className="p-1.5 bg-teal-500/20 rounded-lg">
            <Bot size={18} className="text-teal-400" />
          </div>
          <div>
            <h3 className="text-sm font-bold text-slate-100">Virtual Anup</h3>
            <p className="text-[10px] text-teal-400 font-medium">Powered by Gemini 3</p>
          </div>
        </div>
        <div className="flex items-center gap-1">
          <button onClick={(e) => { e.stopPropagation(); setIsMinimized(!isMinimized); }} className="p-1.5 text-slate-400 hover:text-white hover:bg-white/5 rounded-md">
            {isMinimized ? <Maximize2 size={16} /> : <Minimize2 size={16} />}
          </button>
          <button onClick={(e) => { e.stopPropagation(); setIsOpen(false); }} className="p-1.5 text-slate-400 hover:text-white hover:bg-white/5 rounded-md">
            <X size={16} />
          </button>
        </div>
      </div>

      {!isMinimized && (
        <>
          {/* Messages */}
          <div className="flex-1 overflow-y-auto p-4 space-y-4 hide-scrollbar">
            {messages.map((msg, idx) => (
              <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-3 rounded-2xl text-sm leading-relaxed ${
                  msg.role === 'user' 
                    ? 'bg-teal-600 text-white rounded-tr-none' 
                    : 'bg-slate-800/50 text-slate-200 rounded-tl-none border border-white/5'
                }`}>
                  {msg.text}
                  {msg.isStreaming && <span className="inline-block w-1.5 h-4 ml-1 bg-teal-400 animate-pulse align-middle" />}
                </div>
              </div>
            ))}
            <div ref={messagesEndRef} />
          </div>

          {/* Input */}
          <div className="p-4 bg-slate-900/50 border-t border-white/5">
            <div className="relative">
              <input 
                type="text" 
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                placeholder="Ask something..."
                className="w-full bg-slate-800/50 border border-white/10 rounded-xl pl-4 pr-12 py-3 text-sm text-slate-200 focus:outline-none focus:ring-1 focus:ring-teal-500 focus:border-transparent transition-all"
              />
              <button 
                onClick={handleSend}
                disabled={!input.trim() || isTyping}
                className="absolute right-2 top-1/2 -translate-y-1/2 p-2 text-teal-500 hover:text-teal-400 disabled:opacity-30 transition-colors"
              >
                {isTyping ? <Loader2 size={18} className="animate-spin" /> : <Send size={18} />}
              </button>
            </div>
            <p className="text-[10px] text-slate-500 mt-2 text-center flex items-center justify-center gap-1">
              <Sparkles size={10} /> Recruiter friendly & AI optimized
            </p>
          </div>
        </>
      )}
    </div>
  );
};

